class Solution {
    public int countCharacters(String[] words, String chars) {
        int result = 0;
        for (String word : words) {
            result += countCharactersHelper(word, chars);
        }
        return result;
    }

    private int countCharactersHelper(String word, String chars) {
        int count = 0;
        for (int i = 0; i < word.length(); i++) {
            char c = word.charAt(i);
            if (chars.contains(String.valueOf(c))) {
                count++;
            }
        }
        return count;
    }
}
```

